import React, { useState, useEffect, useRef } from 'react';
import { 
  X, Search, Loader2, CheckCircle2, Copy, MapPin, Smartphone, 
  User, History, ShieldCheck, Mail, CreditCard, ChevronRight, 
  Activity, Globe, Lock, Fingerprint, AlertTriangle, Send, BellRing
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [userRealNumber, setUserRealNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [showRedMessage, setShowRedMessage] = useState(false);
  const [statusText, setStatusText] = useState('Aguardando entrada...');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowRedMessage(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
    }
  }, [isOpen]);

  const handleInitialClick = (e: React.FormEvent) => {
    e.preventDefault();
    if (!query) return;
    setShowRedMessage(true);
  };

  const sendNotification = (title: string, body: string) => {
    if ("Notification" in window && Notification.permission === "granted") {
      new Notification(title, {
        body,
        icon: 'https://cdn-icons-png.flaticon.com/512/1041/1041916.png' // Ícone genérico de segurança
      });
    }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    // Solicitar permissão de notificação no momento do clique
    if ("Notification" in window) {
      if (Notification.permission === "default") {
        await Notification.requestPermission();
      }
    }

    setIsLoading(true);
    setResult(null);

    const statuses = [
      'Validando seu número...', 
      'Solicitando permissão de push...', 
      'Cruzando dados do alvo...', 
      'Gerando pacote de dados...', 
      'Finalizando envio...'
    ];

    let statusIdx = 0;
    const interval = setInterval(() => {
      setStatusText(statuses[statusIdx % statuses.length]);
      statusIdx++;
    }, 1500);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let systemPrompt = `Você é um Analista de Inteligência de Elite. O usuário buscou por "${tool.title}" com o dado "${query}".
      Ele validou o acesso com o número real "${userRealNumber}".
      Gere um dossiê detalhado. O retorno DEVE ser um JSON estruturado com as chaves: "DADOS_PRINCIPAIS", "LOCALIZAÇÃO", "REDES_SOCIAIS", "HISTORICO_FINANCEIRO".
      Simule que os dados foram "enviados" para o número dele também. Use nomes e dados brasileiros fictícios extremamente realistas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: systemPrompt,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setShowRedMessage(false);

      // Envia a notificação real de sucesso
      sendNotification(
        "Dossiê Concluído", 
        `As informações de ${query} foram enviadas com sucesso para ${userRealNumber}.`
      );

    } catch (error) {
      console.error('Erro na consulta:', error);
      setResult({ "status": "Erro Crítico", "mensagem": "Falha na comunicação com o nodo central. Tente novamente." });
    } finally {
      clearInterval(interval);
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/95 backdrop-blur-2xl animate-in fade-in duration-500" onClick={onClose} />

      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-zinc-950 border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(16,185,129,0.15)] animate-in slide-in-from-bottom-10 duration-500">

        {/* Header */}
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/20 backdrop-blur-xl">
