                <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{tool.subtitle}</span>
              </div>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl text-zinc-500 transition-all hover:scale-105 active:scale-95">
            <X size={28} />
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 lg:p-12">

          <div className="max-w-2xl mx-auto space-y-10">

            {/* Initial Search Form */}
            {!showRedMessage && !result && (
              <form onSubmit={handleInitialClick} className="space-y-6">
                <div className="space-y-2">
                   <div className="flex justify-between items-center px-2">
                      <label className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.2em]">Parâmetro de Consulta</label>
                      <div className="flex items-center gap-1.5 text-emerald-500/50 text-[9px] font-bold">
                         <Lock size={10} /> LINK CRIPTOGRAFADO
                      </div>
                   </div>
                   <div className="relative group">
                      <input 
                        ref={inputRef}
                        type="text"
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        placeholder={tool.title.includes('Telefone') ? "(00) 90000-0000" : "Dado do alvo..."}
                        className="w-full bg-zinc-900/50 border-2 border-white/5 rounded-[2rem] py-8 pl-14 pr-8 text-white placeholder-zinc-700 focus:outline-none focus:border-emerald-500/40 focus:bg-zinc-800/30 transition-all text-2xl font-black tracking-tight"
                      />
                      <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-700 group-focus-within:text-emerald-500 transition-colors" size={28} />
                   </div>
                </div>

                <button 
                  type="submit"
                  disabled={!query}
                  className={`action-button w-full py-7 rounded-[2rem] font-black text-xl flex items-center justify-center gap-4 transition-all ${
                    !query ? 'bg-zinc-800 text-zinc-600 opacity-50 shadow-none' : 'text-black'
                  }`}
                >
                  <ShieldCheck size={28} strokeWidth={3} />
                  EXECUTAR CONSULTA
                </button>
              </form>
            )}

            {/* MENSAGEM VERMELHA GRANDE (Solicitação de número real) */}
            {showRedMessage && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300 space-y-8">
                <div className="p-8 lg:p-12 bg-red-600 rounded-[3rem] border-4 border-red-500 shadow-[0_0_50px_rgba(220,38,38,0.4)] text-center space-y-6">
                   <div className="w-20 h-20 bg-white/20 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                      <AlertTriangle size={40} className="text-white" />
                   </div>
                   <h3 className="text-3xl lg:text-4xl font-black text-white leading-none tracking-tighter uppercase">
                     Acesso Bloqueado! <br/> Validação Necessária
                   </h3>
                   <p className="text-red-50 font-bold text-lg leading-snug">
                     Para liberar o dossiê de <span className="bg-white/20 px-2 rounded font-mono">{query}</span>, você deve informar seu NÚMERO REAL abaixo.
                   </p>

                   <div className="flex items-center justify-center gap-2 text-red-100 bg-black/10 py-2 px-4 rounded-full w-fit mx-auto border border-white/10">
                      <BellRing size={14} className="animate-ring" />
                      <span className="text-[10px] font-black uppercase tracking-widest">Ative as notificações para receber o alerta</span>
                   </div>

                   <form onSubmit={handleFinalSearch} className="space-y-4 pt-4">
                      <input 
                        type="text"
                        required
                        value={userRealNumber}
                        onChange={(e) => setUserRealNumber(e.target.value)}
                        placeholder="Digite SEU número real aqui..."
                        className="w-full bg-white rounded-2xl py-6 px-8 text-black placeholder-zinc-400 font-black text-xl focus:outline-none ring-4 ring-red-400/50"
                      />
                      <button 
                        type="submit"
                        className="w-full py-5 bg-zinc-950 text-white rounded-2xl font-black text-lg uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-zinc-900 transition-all shadow-2xl"
                      >
                        <Send size={20} />
                        Liberar Informações Agora
                      </button>
                   </form>
                   <p className="text-red-200/60 text-[10px] font-medium uppercase tracking-[0.2em]">
                     Ao clicar, você autoriza o recebimento de notificações de push do sistema.
                   </p>
                </div>
              </div>
            )}

            {/* Loading State */}
            {isLoading && (
              <div className="mt-20 flex flex-col items-center justify-center space-y-8 animate-in fade-in">
                 <div className="relative">
                    <div className="w-24 h-24 rounded-full border-4 border-emerald-500/20 border-t-emerald-500 animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Activity size={32} className="text-emerald-500 animate-pulse" />
                    </div>
                 </div>
                 <div className="text-center space-y-3">
                    <p className="text-white font-black text-2xl tracking-tighter uppercase italic">{statusText}</p>
                    <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.4em] animate-pulse">Sincronizando com satélites de dados</p>
                 </div>
              </div>
            )}

            {/* Results Display */}
            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 duration-500">
                 <div className="flex items-center justify-between border-b border-white/5 pb-4">
                    <div className="flex items-center gap-3">
                       <CheckCircle2 size={20} className="text-emerald-500" />
                       <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest">Dossiê Gerado e Enviado</h3>
                    </div>
                    <button className="flex items-center gap-2 px-4 py-2 bg-white/5 rounded-xl text-zinc-400 hover:text-white transition-all text-[10px] font-bold uppercase tracking-widest">
                       <Copy size={14} /> Copiar Tudo
                    </button>
                 </div>

                 <div className="grid grid-cols-1 gap-4">
                    {Object.entries(result).map(([section, data]: [string, any], idx) => (
                      <div key={section} className="glass-card p-6 rounded-[2rem] border-white/5 stagger-in" style={{ animationDelay: `${idx * 100}ms` }}>
                        <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                           <Activity size={12} /> {section.replace(/_/g, ' ')}
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                           {typeof data === 'object' ? Object.entries(data).map(([key, value]: [string, any]) => (
                             <div key={key} className="space-y-1">
                                <span className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">{key.replace(/_/g, ' ')}</span>
                                <p className="text-white font-mono-data text-sm font-bold break-words">{String(value)}</p>
                             </div>
                           )) : (
                             <p className="text-white font-mono-data text-sm font-bold col-span-2">{String(data)}</p>
                           )}
                        </div>
                      </div>
                    ))}
                 </div>

                 <div className="p-8 rounded-[2rem] bg-emerald-500/10 border border-emerald-500/20 flex items-start gap-4">
                    <ShieldCheck size={32} className="text-emerald-500 shrink-0" />
                    <div>
                       <p className="text-white font-bold text-sm uppercase tracking-widest mb-1">Confirmação de Envio</p>
                       <p className="text-xs text-zinc-400 font-medium leading-relaxed">
                          Uma cópia completa deste dossiê foi enviada para o número <span className="text-white font-bold">{userRealNumber}</span>. 
                          O histórico de busca foi deletado de nossos servidores para sua segurança.
                       </p>
                    </div>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SearchModal;

import path from 'path';
import { fileURLToPath } from 'url';
import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

// Fix: __dirname is not available in ESM, we need to define it manually
const __dirname = path.dirname(fileURLToPath(import.meta.url));

export default defineConfig(({ mode }) => {
    const env = loadEnv(mode, '.', '');
    return {
      server: {
        port: 3000,
        host: '0.0.0.0',
      },
      plugins: [react()],
      define: {
        'process.env.API_KEY': JSON.stringify(env.GEMINI_API_KEY),
        'process.env.GEMINI_API_KEY': JSON.stringify(env.GEMINI_API_KEY)
      },
      resolve: {
        alias: {
          '@': path.resolve(__dirname, '.'),
        }
      }
    };
});

import { GoogleGenAI } from "@google/genai";

export const generateMockResult = async (toolName: string, query: string) => {
  try {
    // Fix: Instantiate the GoogleGenAI client right before the API call to ensure use of the correct environment key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Gere um resultado de consulta de dados fictício mas realista para a ferramenta "${toolName}" usando o parâmetro "${query}". Retorne um objeto JSON formatado.`,
      config: {
        responseMimeType: "application/json"
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Error:", error);
    return { error: "Não foi possível processar a consulta agora." };
  }
};

