import React, { useState, useEffect, useRef } from 'react';
import { 
  X, Search, Loader2, CheckCircle2, Copy, MapPin, Smartphone, 
  User, History, ShieldCheck, Mail, CreditCard, ChevronRight, 
  Activity, Globe, Lock, Fingerprint, AlertTriangle, Send, BellRing,
  Camera, Scan
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [userRealNumber, setUserRealNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [showRedMessage, setShowRedMessage] = useState(false);
  const [statusText, setStatusText] = useState('Aguardando entrada...');
  const [isScanning, setIsScanning] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowRedMessage(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setIsScanning(false);
    }
  }, [isOpen]);

  const handleInitialClick = (e: React.FormEvent) => {
    e.preventDefault();
    if (!query) return;
    setShowRedMessage(true);
  };

  const sendNotification = (title: string, body: string) => {
    if ("Notification" in window && Notification.permission === "granted") {
      new Notification(title, {
        body,
        icon: 'https://cdn-icons-png.flaticon.com/512/1041/1041916.png'
      });
    }
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      return stream;
    } catch (err) {
      console.warn("Câmera negada ou não disponível:", err);
      return null;
    }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    // 1. Pedir Notificações
    if ("Notification" in window && Notification.permission === "default") {
      await Notification.requestPermission();
    }

    setIsLoading(true);
    setResult(null);
    setStatusText('Iniciando protocolos de segurança...');

    // 2. Pedir Câmera e Iniciar Scan Biométrico
    setIsScanning(true);
    const stream = await startCamera();

    const statuses = [
      'Ativando câmera frontal...',
      'Escaneando biometria facial...', 
      'Verificando integridade do acesso...',
      'Validando número de telefone...', 
      'Consultando bases governamentais...', 
      'Gerando pacote criptografado...'
    ];

    let statusIdx = 0;
    const interval = setInterval(() => {
      setStatusText(statuses[statusIdx % statuses.length]);
      statusIdx++;

      // Desativa o visual da câmera após alguns segundos para simular sucesso
      if (statusIdx === 3) setIsScanning(false);
    }, 2000);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let systemPrompt = `Você é um Analista de Inteligência de Elite. O usuário buscou por "${tool.title}" com o dado "${query}".
      Ele validou o acesso com o número "${userRealNumber}" e passou pela verificação biométrica.
      Gere um dossiê detalhado em JSON com chaves: "DADOS_IDENTIFICADOS", "VINCULOS", "ALERTA_SEGURANCA", "LOCALIZACAO_APROXIMADA".
      Use dados fictícios brasileiros extremamente realistas.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: systemPrompt,
        config: { responseMimeType: "application/json" }
      });

      // Parar a câmera
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setShowRedMessage(false);

      sendNotification(
        "Acesso Autorizado", 
        `Dossiê de ${query} liberado. Verificação biométrica concluída com sucesso.`
      );

    } catch (error) {
      console.error('Erro:', error);
      setResult({ "status": "Erro de Autenticação", "mensagem": "Falha na verificação de identidade." });
    } finally {
      clearInterval(interval);
      setIsLoading(false);
      setIsScanning(false);
    }
