        {/* Header */}
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/20 backdrop-blur-xl">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg ${tool.isPremium ? 'bg-emerald-500/20 text-emerald-500' : 'bg-blue-500/20 text-blue-500'}`}>
               <Fingerprint size={32} strokeWidth={1.5} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white tracking-tighter uppercase leading-none mb-1">{tool.title}</h2>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{tool.subtitle}</span>
              </div>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl text-zinc-500 transition-all hover:scale-105 active:scale-95">
            <X size={28} />
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 lg:p-12">

          <div className="max-w-2xl mx-auto space-y-10">

            {/* Initial Search Form */}
            {!showRedMessage && !result && (
              <form onSubmit={handleInitialClick} className="space-y-6">
                <div className="space-y-2">
                   <div className="flex justify-between items-center px-2">
                      <label className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.2em]">Parâmetro de Consulta</label>
                      <div className="flex items-center gap-1.5 text-emerald-500/50 text-[9px] font-bold">
                         <Lock size={10} /> LINK CRIPTOGRAFADO
                      </div>
                   </div>
                   <div className="relative group">
                      <input 
                        ref={inputRef}
                        type="text"
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        placeholder={tool.title.includes('Telefone') ? "(00) 90000-0000" : "Dado do alvo..."}
                        className="w-full bg-zinc-900/50 border-2 border-white/5 rounded-[2rem] py-8 pl-14 pr-8 text-white placeholder-zinc-700 focus:outline-none focus:border-emerald-500/40 focus:bg-zinc-800/30 transition-all text-2xl font-black tracking-tight"
                      />
                      <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-700 group-focus-within:text-emerald-500 transition-colors" size={28} />
                   </div>
                </div>

                <button 
                  type="submit"
                  disabled={!query}
                  className={`w-full py-7 rounded-[2rem] font-black text-xl flex items-center justify-center gap-4 transition-all border-2 ${
                    !query 
                      ? 'bg-zinc-900/50 border-white/5 text-zinc-700 opacity-50 shadow-none cursor-not-allowed' 
                      : 'bg-emerald-500 border-emerald-400 text-black shadow-[0_0_40px_rgba(16,185,129,0.3)] hover:scale-[1.02] active:scale-95'
                  }`}
                >
                  <ShieldCheck size={28} strokeWidth={3} />
                  EXECUTAR CONSULTA
                </button>
              </form>
            )}

            {/* MENSAGEM VERMELHA GRANDE (Validação de Número + Menção Biometria) */}
            {showRedMessage && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300 space-y-8">
                <div className="p-8 lg:p-12 bg-red-600 rounded-[3rem] border-4 border-red-500 shadow-[0_0_50px_rgba(220,38,38,0.4)] text-center space-y-6">
                   <div className="w-20 h-20 bg-white/20 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                      <AlertTriangle size={40} className="text-white" />
                   </div>
                   <h3 className="text-3xl lg:text-4xl font-black text-white leading-none tracking-tighter uppercase">
                     Autenticação em Duas Etapas
                   </h3>
                   <p className="text-red-50 font-bold text-lg leading-snug">
                     O sistema exige validação telefônica e <span className="underline">reconhecimento facial</span> para liberar os dados de <span className="bg-white/20 px-2 rounded font-mono">{query}</span>.
                   </p>

                   <div className="flex flex-col gap-2 items-center">
                     <div className="flex items-center justify-center gap-2 text-red-100 bg-black/10 py-2 px-4 rounded-full w-fit border border-white/10">
                        <BellRing size={14} className="animate-ring" />
                        <span className="text-[10px] font-black uppercase tracking-widest">Notificações</span>
                     </div>
                     <div className="flex items-center justify-center gap-2 text-red-100 bg-black/10 py-2 px-4 rounded-full w-fit border border-white/10">
                        <Camera size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Biometria Facial</span>
                     </div>
                   </div>

                   <form onSubmit={handleFinalSearch} className="space-y-4 pt-4">
                      <input 
                        type="text"
                        required
                        value={userRealNumber}
                        onChange={(e) => setUserRealNumber(e.target.value)}
                        placeholder="Seu número (WhatsApp)..."
                        className="w-full bg-white rounded-2xl py-6 px-8 text-black placeholder-zinc-400 font-black text-xl focus:outline-none ring-4 ring-red-400/50"
                      />
                      <button 
                        type="submit"
                        className="w-full py-5 bg-zinc-950 text-white rounded-2xl font-black text-lg uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-zinc-900 transition-all shadow-2xl"
                      >
                        <Scan size={20} />
                        Iniciar Validação Facial
                      </button>
                   </form>
                   <p className="text-red-200/60 text-[10px] font-medium uppercase tracking-[0.2em]">
                     Ao clicar, o navegador solicitará acesso à sua câmera frontal.
                   </p>
                </div>
              </div>
            )}

            {/* Loading State com Preview de Câmera (Simulado/Real) */}
            {isLoading && (
              <div className="mt-10 flex flex-col items-center justify-center space-y-10 animate-in fade-in">

                 {isScanning && (
                   <div className="relative w-64 h-64 lg:w-80 lg:h-80 rounded-full border-4 border-emerald-500/50 overflow-hidden bg-black shadow-[0_0_50px_rgba(16,185,129,0.2)]">
                      <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        muted 
                        className="absolute inset-0 w-full h-full object-cover scale-x-[-1] opacity-60"
                      />
                      {/* Laser Line Effect */}
                      <div className="absolute left-0 right-0 h-1 bg-emerald-500 shadow-[0_0_20px_#10b981] z-10 animate-[scan_3s_ease-in-out_infinite]"></div>
                      <style>{`
                        @keyframes scan {
                          0%, 100% { top: 0%; }
                          50% { top: 100%; }
                        }
                      `}</style>
                      <div className="absolute inset-0 border-[20px] border-black/20 pointer-events-none"></div>
                   </div>
                 )}

                 {!isScanning && (
                    <div className="relative">
                      <div className="w-24 h-24 rounded-full border-4 border-emerald-500/20 border-t-emerald-500 animate-spin"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Activity size={32} className="text-emerald-500 animate-pulse" />
                      </div>
                    </div>
                 )}

                 <div className="text-center space-y-3">
                    <p className="text-white font-black text-2xl tracking-tighter uppercase italic">{statusText}</p>
                    <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.4em] animate-pulse">
                      {isScanning ? "Mantenha o rosto visível para autenticação" : "Finalizando varredura de dados"}
                    </p>
                 </div>
              </div>
            )}

            {/* Results Display */}
            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 duration-500">
                 <div className="flex items-center justify-between border-b border-white/5 pb-4">
                    <div className="flex items-center gap-3">
                       <CheckCircle2 size={20} className="text-emerald-500" />
                       <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest">Dossiê de Alta Precisão Liberado</h3>
                    </div>
                 </div>

                 <div className="grid grid-cols-1 gap-4">
                    {Object.entries(result).map(([section, data]: [string, any], idx) => (
                      <div key={section} className="glass-card p-6 rounded-[2rem] border-white/5 stagger-in" style={{ animationDelay: `${idx * 100}ms` }}>
