                       <p className="text-white font-bold text-sm uppercase tracking-widest mb-1">Criptografia de Ponta-a-Ponta</p>
                       <p className="text-xs text-zinc-400 font-medium leading-relaxed">
                          Acesso autorizado via biometria facial. Os dados acima foram espelhados para o terminal <span className="text-white font-bold">{userRealNumber}</span> via canal seguro.
                       </p>
                    </div>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

