const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

// Registro do Service Worker
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    // Usando caminho relativo para evitar erros de origem em ambientes de preview/proxy
    // O uso de 'sw.js' sem a barra inicial resolve relativo ao diretório atual da página.
    navigator.serviceWorker.register('sw.js')
      .then(reg => console.log('Service Worker registrado com sucesso:', reg.scope))
      .catch(err => {
        console.error('Falha ao registrar Service Worker:', err);
        // Fallback: tenta registrar garantindo que a URL seja do origin atual
        if (err.name === 'SecurityError') {
           const swPath = window.location.pathname.substring(0, window.location.pathname.lastIndexOf('/') + 1) + 'sw.js';
           navigator.serviceWorker.register(swPath)
             .then(reg => console.log('Service Worker registrado via fallback:', reg.scope))
             .catch(e => console.error('Falha total no registro do SW:', e));
        }
      });
  });
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

