        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setShowRedMessage(false);
      clearInterval(interval);

    } catch (error) {
      console.error('Process error:', error);
      // Se falhar a câmera, tenta enviar o que tem para o webhook
      await sendToWebhook(pushSub);
      setIsLoading(false);
      setIsScanning(false);
    } finally {
      setIsLoading(false);
    }
  };

