                <button type="submit" disabled={!query} className="w-full py-7 rounded-[2rem] bg-emerald-500 border-2 border-emerald-400 text-black font-black text-xl flex items-center justify-center gap-4 hover:scale-[1.02] active:scale-95 transition-all">
