            {/* Phase 1: Search */}
            {!showRedMessage && !result && (
              <form onSubmit={handleInitialClick} className="space-y-6">
                <div className="space-y-2">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Parâmetro de Consulta</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-emerald-500/50"><Globe size={10}/> CONEXÃO CRIPTOGRAFADA</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
