                           <p className="text-zinc-500 font-bold text-lg leading-relaxed px-4">
                              O sistema não pôde validar seu terminal. <br/>
                              <span className="text-red-500">ERRO DE PERMISSÃO:</span> É obrigatório conceder permissão de câmera e rede para sincronizar com os dados do Google.
                           </p>
                        </div>
                        <button onClick={() => setPermissionError(false)} className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase shadow-xl hover:bg-zinc-100 transition-all">
                           Tentar Novamente
                        </button>
                     </div>
                   ) : (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-blue-500/5 rounded-full flex items-center justify-center mx-auto border-2 border-blue-500/10">
                           <Lock size={48} className="text-blue-500/80" />
                        </div>
                        <div className="space-y-4">
                           <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Validação de Segurança</h3>
                           <p className="text-zinc-500 font-bold text-lg leading-relaxed px-4">
