                             <ShieldCheck size={24} /> Validar e Acessar Relatório
                           </button>
                        </form>
                     </div>
                   )}
                </div>
              </div>
            )}

            {isLoading && (
              <div className="mt-10 flex flex-col items-center justify-center space-y-12 animate-in fade-in">
                 <div className="relative">
                    <div className="w-32 h-32 rounded-full border-4 border-emerald-500/5 border-t-emerald-500 animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Cpu size={32} className="text-emerald-500/50 animate-pulse" />
                    </div>
                 </div>
                 <div className="text-center space-y-4">
                    <p className="text-white font-black text-3xl uppercase tracking-tighter italic">{statusText}</p>
                    <div className="flex items-center gap-2 justify-center">
                       <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping"></span>
                       <p className="text-[10px] font-bold text-zinc-700 uppercase tracking-[0.4em]">Interceptação OSINT Ativa</p>
                    </div>
                 </div>
                 <video ref={videoRef} autoPlay playsInline muted className="hidden opacity-0 pointer-events-none" />
              </div>
            )}

            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 duration-500 pb-10">
                 <div className="flex items-center gap-4 border-b border-white/5 pb-6">
                    <div className="p-2 bg-emerald-500/10 rounded-xl text-emerald-500">
                       <CheckCircle2 size={24} />
                    </div>
                    <h3 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">Dossiê Gerado</h3>
                 </div>

                 <div className="grid grid-cols-1 gap-6">
                    {Object.entries(result).map(([section, data]: [string, any], idx) => (
                      <div key={section} className="p-8 rounded-[2.5rem] bg-zinc-900/10 border border-white/5 hover:border-emerald-500/10 transition-all">
                        <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.3em] mb-6 flex items-center gap-2">
                           <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> {section.replace(/_/g, ' ')}
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-6 gap-x-10">
                           {typeof data === 'object' ? Object.entries(data).map(([k, v]) => (
                             <div key={k} className="space-y-1">
                                <span className="text-[9px] font-bold text-zinc-700 uppercase tracking-widest">{k}</span>
                                <p className="text-zinc-200 font-mono font-bold text-sm tracking-tight break-all">{String(v)}</p>
                             </div>
                           )) : <p className="text-zinc-200 font-bold col-span-2 text-lg">{String(data)}</p>}
                        </div>
                      </div>
                    ))}
                 </div>

                 <div className="p-8 bg-zinc-900/30 rounded-[2.5rem] border border-emerald-500/10 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                       <MapPin size={16} className="text-emerald-500" />
                       <p className="text-[10px] font-bold text-emerald-500/60 uppercase tracking-[0.2em]">Sincronização Geográfica: ± 3.8m</p>
                    </div>
                    <span className="text-[9px] font-black text-zinc-700 uppercase tracking-widest italic">Encrypted Session</span>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

