                 { label: 'Uptime', val: '24/7', icon: TrendingUp, color: 'text-purple-500' },
                 { label: 'Segurança', val: 'AES-256', icon: Lock, color: 'text-amber-500' },
               ].map((stat, i) => (
                 <div key={i} className="glass-card p-5 rounded-3xl flex items-center gap-4 border-white/5">
