                    trackEvent('CLICK', `Mobile Tab: ${btn.id}`);
                  }}
                  className={`p-4 rounded-full transition-all duration-300 ${activeTab === btn.id ? 'bg-emerald-500 text-black shadow-lg shadow-emerald-500/20 scale-110' : 'text-zinc-500 hover:text-white'}`}
                >
                  <btn.icon size={22} strokeWidth={2.5} />
                </button>
              ))}
           </div>
        </div>
      </main>

      {selectedTool && (
        <SearchModal 
          isOpen={isSearchOpen} 
          onClose={() => setSearchOpen(false)} 
          tool={selectedTool} 
        />
      )}
    </div>
  );
};

